//! GPUI actions and opt-in default key bindings for the editor component.

use gpui::*;

pub const BLOCK_EDITOR_CONTEXT: &str = "MarkdownEditor";

actions!(
    gpui_markdown_editor,
    [
        Newline,
        DeleteBack,
        Delete,
        WordDeleteBack,
        WordDeleteForward,
        FocusPrev,
        FocusNext,
        MoveLeft,
        MoveRight,
        WordMoveLeft,
        WordMoveRight,
        Home,
        End,
        BlockUp,
        BlockDown,
        PageUp,
        PageDown,
        JumpToTop,
        JumpToBottom,
        SelectLeft,
        SelectRight,
        WordSelectLeft,
        WordSelectRight,
        SelectHome,
        SelectEnd,
        SelectAll,
        Copy,
        Cut,
        Paste,
        Undo,
        Redo,
        BoldSelection,
        ItalicSelection,
        UnderlineSelection,
        CodeSelection,
        IndentBlock,
        OutdentBlock,
        ExitCodeBlock,
        DismissTransientUi,
        ToggleViewMode
    ]
);

/// Default editor bindings. Hosts may omit or replace these before mounting
/// the component; importing the crate never mutates global application state.
pub fn default_key_bindings() -> Vec<KeyBinding> {
    vec![
        KeyBinding::new("enter", Newline, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("backspace", DeleteBack, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("delete", Delete, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-backspace", WordDeleteBack, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("alt-backspace", WordDeleteBack, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-delete", WordDeleteForward, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("alt-delete", WordDeleteForward, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("up", FocusPrev, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("down", FocusNext, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("left", MoveLeft, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("right", MoveRight, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-left", WordMoveLeft, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("alt-left", WordMoveLeft, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-right", WordMoveRight, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("alt-right", WordMoveRight, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("home", Home, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("end", End, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-up", BlockUp, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("alt-up", BlockUp, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-down", BlockDown, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("alt-down", BlockDown, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("pageup", PageUp, None),
        KeyBinding::new("pagedown", PageDown, None),
        KeyBinding::new("ctrl-home", JumpToTop, None),
        KeyBinding::new("cmd-up", JumpToTop, None),
        KeyBinding::new("ctrl-end", JumpToBottom, None),
        KeyBinding::new("cmd-down", JumpToBottom, None),
        KeyBinding::new("shift-left", SelectLeft, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("shift-right", SelectRight, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new(
            "ctrl-shift-left",
            WordSelectLeft,
            Some(BLOCK_EDITOR_CONTEXT),
        ),
        KeyBinding::new("alt-shift-left", WordSelectLeft, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new(
            "ctrl-shift-right",
            WordSelectRight,
            Some(BLOCK_EDITOR_CONTEXT),
        ),
        KeyBinding::new(
            "alt-shift-right",
            WordSelectRight,
            Some(BLOCK_EDITOR_CONTEXT),
        ),
        KeyBinding::new("shift-home", SelectHome, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("shift-end", SelectEnd, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("cmd-a", SelectAll, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-a", SelectAll, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("cmd-c", Copy, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-c", Copy, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("cmd-x", Cut, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-x", Cut, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("cmd-v", Paste, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-v", Paste, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("cmd-z", Undo, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-z", Undo, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("cmd-shift-z", Redo, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-y", Redo, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("cmd-b", BoldSelection, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-b", BoldSelection, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("cmd-i", ItalicSelection, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-i", ItalicSelection, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("cmd-u", UnderlineSelection, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-u", UnderlineSelection, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("cmd-`", CodeSelection, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-`", CodeSelection, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("tab", IndentBlock, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("shift-tab", OutdentBlock, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("cmd-enter", ExitCodeBlock, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("ctrl-enter", ExitCodeBlock, Some(BLOCK_EDITOR_CONTEXT)),
        KeyBinding::new("escape", DismissTransientUi, None),
        KeyBinding::new("ctrl-tab", ToggleViewMode, None),
        KeyBinding::new("cmd-tab", ToggleViewMode, None),
    ]
}
